#include<bits/stdc++.h>
using namespace std;
int a[100010],n;
vector<pair<int,int>> mp[100010];
struct _01trie
{
    int son[3200010][2],cnt;
    _01trie()
    {
        cnt=0;
        memset(son,0,sizeof(son));
    }
    void insert(int x)
    {
        int p=0;
        for(int i=31;i>=0;i--)
        {
            int tmp=(x>>i)&1;
            if(!son[p][tmp])
            {
                son[p][tmp]=++cnt;
            }
            p=son[p][tmp];
        }
    }
    int query(int x)
    {
        int p=0,ans=0;
        for(int i=31;i>=0;i--)
        {
            int tmp=(x>>i)&1;
            if(son[p][tmp^1])
            {
                ans|=(1<<i);
                p=son[p][tmp^1];
            }
            else
            {
                p=son[p][tmp];
            }
        }
        return ans;
    }
}t;
void dfs(int x,int fa=-1)
{
